problem:
How many diagonals does hexagon $ABCDEF$ have?

[asy]size(101);
string[] labels = {"$C$","$B$","$A$","$F$","$E$","$D$"};
path p;
for(int i = 0; i<6; ++i)
{
p = p--dir(360*i/6);
label(labels[i],dir(360*i/6),dir(360*i/6),fontsize(10pt));
}
draw(p--cycle);
label("1",(0,1.03),fontsize(10));[/asy]

